		display: flex;
		flex-grow: 1;
		flex-direction: column;
		width: var(--size-full);
		font-weight: var(--body-text-weight);
		font-size: var(--body-text-size);
	}

	main.contain {
		display: flex;
		flex-direction: column;
	}

	footer {
		display: flex;
